在即将到来的Vue3.0中，Vue数据的响应式系统采用了ES6的Proxy来代替Object.defineProperty

Object.defineProperty ：兼容主流浏览器和ie9以上的ie浏览器，能够监听数据对象的变化，但是监听不到对象属性的增删、数组元素和长度的变化，同时会在vue初始化的时候把所有的Observer都建立好，才能观察到数据对象属性的变化。
Proxy : 可以做到监听对象属性的增删和数组元素和长度的修改，还可以监听Map、Set、WeakSet、WeakMap，同时还实现了惰性的监听，不会在初始化的时候创建所有的Observer，而是会在用到的时候才去监听。


Proxy语法：Proxy 对象用于定义基本操作的自定义行为（如属性查找、赋值、枚举、函数调用等）。Proxy 可以理解成，在目标对象之前架设一层“拦截”，外界对该对象的访问，都必须先通过这层拦截，因此提供了一种机制，可以对外界的访问进行过滤和改写。
const p &#x3D; new Proxy(target, handler)

参数：


target : 要使用 Proxy 包装的目标对象（可以是任何类型的对象，包括原生数组，函数，甚至另一个代理）。  
handler: 一个通常以函数作为属性的对象，各属性中的函数分别定义了在执行各种操作时代理 p 的行为。


Proxy – api:
  Proxy.revocable()
创建一个可撤销的Proxy对象。
handler 对象的方法  对象是一个容纳一批特定属性的占位符对象。它包含有 Proxy 的各个捕获器（trap）。 所有的捕捉器是可选的。如果没有定义某个捕捉器，那么就会保留源对象的默认行为。
  &#x2F;&#x2F;  Proxy 支持的拦截操作一览，一共 13 种。
        get(target, propKey, receiver)： 
        &#x2F;&#x2F; 拦截对象属性的读取， 比如proxy.foo和proxy[&#39;foo&#39;]。

        set(target, propKey, value, receiver)： 
        &#x2F;&#x2F; 拦截对象属性的设置， 比如proxy.foo &#x3D; v或proxy[&#39;foo&#39;] &#x3D; v， 返回一个布尔值。

        has(target, propKey)： 
        &#x2F;&#x2F; 拦截propKey in proxy的操作， 返回一个布尔值。

        deleteProperty(target, propKey)： 
        &#x2F;&#x2F; 拦截delete proxy[propKey] 的操作， 返回一个布尔值。

        ownKeys(target):
        &#x2F;&#x2F; 拦截Object.getOwnPropertyNames(proxy)、Object.getOwnPropertySymbols(proxy)、Object.keys(proxy)、for...in循环，返回一个数组。该方法返回目标对象所有自身的属性的属性名，而Object.keys()的返回结果仅包括目标对象自身的可遍历属性。

        getOwnPropertyDescriptor(target, propKey)：
        &#x2F;&#x2F; 拦截Object.getOwnPropertyDescriptor(proxy, propKey)，返回属性的描述对象。

        defineProperty(target, propKey, propDesc)：
        &#x2F;&#x2F; 拦截Object.defineProperty(proxy, propKey, propDesc）、Object.defineProperties(proxy, propDescs)，返回一个布尔值。

        preventExtensions(target)：
        &#x2F;&#x2F; 拦截Object.preventExtensions(proxy)，返回一个布尔值。

        getPrototypeOf(target)：
        &#x2F;&#x2F; 拦截Object.getPrototypeOf(proxy)，返回一个对象。

        isExtensible(target)：
        &#x2F;&#x2F; 拦截Object.isExtensible(proxy)，返回一个布尔值。

        setPrototypeOf(target, proto)：
        &#x2F;&#x2F; 拦截Object.setPrototypeOf(proxy, proto)，返回一个布尔值。如果目标对象是函数，那么还有两种额外操作可以拦截。

        apply(target, object, args)：
        &#x2F;&#x2F; 拦截 Proxy 实例作为函数调用的操作，比如proxy(...args)、proxy.call(object, ...args)、proxy.apply(...)。

        construct(target, args)：
        &#x2F;&#x2F; 拦截 Proxy 实例作为构造函数调用的操作，比如new proxy(...args)。

关于 Refect
Reflect对象与Proxy对象一样，也是 ES6 为了操作对象而提供的新 API
Reflect与Proxy--handler对象的方法是一一对应的;  关于Reflect的详情了解 点击了解ES6 =&gt; Reflect

get() 与 set()
get=&gt; 方法用于拦截某个属性的读取操作，可以接受三个参数，依次为目标对象、属性名和 proxy 实例本身（严格地说，是操作行为所针对的对象），其中最后一个参数可选。
set =&gt; 方法用来拦截某个属性的赋值操作，可以接受四个参数，依次为目标对象、属性名、属性值和 Proxy 实例本身，其中最后一个参数可选。

&#x2F;&#x2F; new Proxy(target,handler); &#x3D;&#x3D;&gt; 参数简介
&#x2F;&#x2F; target &#x3D;&gt; 要进行拦截的对象
&#x2F;&#x2F; handler &#x3D;&gt; 要求是一个对象，用于定制拦截的行为，及逻辑处理
&#x2F;&#x2F; &#x3D;&gt; 如果handler是一个空对象，就不会有任何的拦截处理，访问 py 这个实例效果同于访问 target。

let obj &#x3D; &#123;
    name: &quot;Proxy&quot;,
&#125;

let py &#x3D; new Proxy(obj, &#123;
   get(target, key, example) &#123;
       &#x2F;&#x2F; target &#x3D;&gt; obj:&#123;name:&quot;Proxy&quot;&#125;
       &#x2F;&#x2F; key &#x3D;&gt; 每次要获取的属性名 propKey
       &#x2F;&#x2F; example &#x3D;&gt; 当前 py 这个实例

       return Reflect.get(target, key);
       &#x2F;&#x2F; return &quot;default&quot;; 每次都会获取到固定返回值
   &#125;,
   set(target, key, newValue, example) &#123;
       &#x2F;&#x2F; console.log(target, key, value, example);
       &#x2F;&#x2F; newValue &#x3D;&gt; 将要设置的新值  
       if (Reflect.get(target, key) !&#x3D;&#x3D; newValue) &#123;
           Reflect.set(target, key, newValue);
       &#125;
   &#125;
&#125;);

&#x2F;&#x2F; get
console.log(py.name); &#x2F;&#x2F;&#x3D;&gt; &quot;Proxy&quot;
console.log(py.age); &#x2F;&#x2F;&#x3D;&gt; undefined

&#x2F;&#x2F; set
py.age &#x3D; &quot;20&quot;;
py.name &#x3D; &quot;newProxy&quot;;

console.log(py);
console.log(obj);



Proxy 实例也可以作为其他对象的原型对象。let py &#x3D; new Proxy(&#123;&#125;, &#123;
    get(target, key, example) &#123;
        &#x2F;&#x2F; if (key &#x3D;&#x3D;&#x3D; &quot;__proto__&quot;) return example;  
        return &quot;default&quot;;
    &#125;,
    set(target, key, newValue) &#123;
        Reflect.set(target, key, newValue);
    &#125;
&#125;);

let obj &#x3D; Object.create(py);
console.log(obj.df); &#x2F;&#x2F;&#x3D;&gt; &quot;default&quot;
console.log(obj.__proto__); &#x2F;&#x2F;&#x3D;&gt; &quot;default&quot;
console.log(obj.prototype); &#x2F;&#x2F;&#x3D;&gt; &quot;default&quot;
&#x2F;&#x2F; 要留意取值的操作处理


阮一峰ES6-Proxy 文档中，使用get拦截，实现数组读取负数的索引
function createArray(...elements) &#123;
  let handler &#x3D; &#123;
    get(target, propKey, receiver) &#123;
      let index &#x3D; Number(propKey);
      if (index &lt; 0) &#123;
        propKey &#x3D; String(target.length + index);
      &#125;
      return Reflect.get(target, propKey, receiver);
    &#125;
  &#125;;

  let target &#x3D; [];
  target.push(...elements);
  return new Proxy(target, handler);
&#125;

let arr &#x3D; createArray(&#39;a&#39;, &#39;b&#39;, &#39;c&#39;);
arr[-1] &#x2F;&#x2F; c
上面代码中，数组的位置参数是-1，就会输出数组的倒数第一个成员。
利用 Proxy，可以将读取属性的操作（get），转变为执行某个函数，从而实现属性的链式操作。
var pipe &#x3D; function (value) &#123;
  var funcStack &#x3D; [];
  var oproxy &#x3D; new Proxy(&#123;&#125; , &#123;
    get : function (pipeObject, fnName) &#123;
      if (fnName &#x3D;&#x3D;&#x3D; &#39;get&#39;) &#123;
        return funcStack.reduce(function (val, fn) &#123;
          return fn(val);
        &#125;,value);
      &#125;
      funcStack.push(window[fnName]);
      return oproxy;
    &#125;
  &#125;);

  return oproxy;
&#125;

var double &#x3D; n &#x3D;&gt; n * 2;
var pow    &#x3D; n &#x3D;&gt; n * n;
var reverseInt &#x3D; n &#x3D;&gt; n.toString().split(&quot;&quot;).reverse().join(&quot;&quot;) | 0;

pipe(3).double.pow.reverseInt.get; &#x2F;&#x2F; 63
上面代码设置 Proxy 以后，达到了将函数名链式使用的效果。
实例：使用 Proxy 实现观察者模式观察者模式（Observer mode）指的是函数自动观察数据对象，一旦对象有变化，函数就会自动执行。
const person &#x3D; observable(&#123;
  name: &#39;张三&#39;,
  age: 20
&#125;);

function print() &#123;
  console.log(&#96;$&#123;person.name&#125;, $&#123;person.age&#125;&#96;)
&#125;

observe(print);
person.name &#x3D; &#39;李四&#39;;
&#x2F;&#x2F; 输出
&#x2F;&#x2F; 李四, 20
上面代码中，数据对象person是观察目标，函数print是观察者。一旦数据对象发生变化，print就会自动执行。
下面，使用 Proxy 写一个观察者模式的最简单实现，即实现observable和observe这两个函数。思路是observable函数返回一个原始对象的 Proxy 代理，拦截赋值操作，触发充当观察者的各个函数。
const queuedObservers &#x3D; new Set();

const observe &#x3D; fn &#x3D;&gt; queuedObservers.add(fn);
const observable &#x3D; obj &#x3D;&gt; new Proxy(obj, &#123;set&#125;);

function set(target, key, value, receiver) &#123;
  const result &#x3D; Reflect.set(target, key, value, receiver);
  queuedObservers.forEach(observer &#x3D;&gt; observer());
  return result;
&#125;
上面代码中，先定义了一个Set集合，所有观察者函数都放进这个集合。然后，observable函数返回原始对象的代理，拦截赋值操作。拦截函数set之中，会自动执行所有观察者。
了解更多的实例介绍，和其他拦截操作的方法介绍 =&gt; ES6-Proxy

MVC &amp; MVVM
传统操作DOM模式
MVC：model view controller
MVVM：model view viewModel


双向数据绑定的实现原理
Object.defineProperty
实现的底层原理  :   	&#x2F;&#x2F;obServer:观察者
function obServer(obj) &#123;
    if (obj &amp;&amp; typeof obj &#x3D;&#x3D;&#x3D; &#39;object&#39;) &#123;
        for (let key in obj) &#123;
            if (!obj.hasOwnProperty(key)) break;
            defineReactive(obj, key, obj[key]);
        &#125;
    &#125;
&#125;

function defineReactive(obj, key, value) &#123;
    obServer(value);
    Object.defineProperty(obj, key, &#123;
        get() &#123;
            return value;
        &#125;,
        set(newValue) &#123;
            observer(newValue);
            if (value &#x3D;&#x3D;&#x3D; newValue) return;
            value &#x3D; newValue;
        &#125;
    &#125;);
&#125;

function $set(data, key, value) &#123;
    defineReactive(data, key, value);
&#125;

核心原理及代码实现

解析Vue指令的  —— v-model
编译Vue中的取值语法 —— &#123; &#123;...&#125; &#125;
实现对表单元素input 双向数据监听 

这次使用ES6定义class类的形式来实现。就不使用ES5了
&lt;!DOCTYPE html&gt;
&lt;html lang&#x3D;&quot;&quot;&gt;

&lt;head&gt;
    &lt;meta charset&#x3D;&quot;UTF-8&quot;&gt;
    &lt;meta name&#x3D;&quot;viewport&quot; content&#x3D;&quot;width&#x3D;device-width, initial-scale&#x3D;1.0&quot;&gt;
    &lt;title&gt;Vue-MVVM&lt;&#x2F;title&gt;
&lt;&#x2F;head&gt;

&lt;body&gt;
    &lt;div id&#x3D;&quot;app&quot;&gt;
        &lt;p a&#x3D;&quot;21&quot;&gt;&#123;&#123; msg &#125;&#125; &amp;nbsp; 这是静态文本&lt;&#x2F;p&gt;
        &lt;input type&#x3D;&quot;text&quot; v-model&#x3D;&quot;val&quot;&gt;
        &lt;div&gt;
            &lt;p&gt;&#123;&#123; val &#125;&#125; 静态文本&lt;&#x2F;p&gt;
        &lt;&#x2F;div&gt;
    &lt;&#x2F;div&gt;

    &lt;script src&#x3D;&quot;https:&#x2F;&#x2F;cdn.jsdelivr.net&#x2F;npm&#x2F;vue&#x2F;dist&#x2F;vue.js&quot;&gt;&lt;&#x2F;script&gt;
    &lt;script&gt;
        &#x2F;* 
         * obServer: 数据监听（拦截）
         * compile: 指令解析
         * Dep: 订阅器（事件池，发布器）
         * Watcher: 订阅者：（订阅）
         *&#x2F;

        &#x2F;&#x2F; Dep
        class Dep &#123;
            constructor() &#123;
                this.subs &#x3D; [];
            &#125;
            subscribe(sub) &#123;
                this.subs.push(sub);
            &#125;
            notify(oldValue) &#123;
                console.log(this.subs);

                this.subs.forEach(item &#x3D;&gt; &#123;
                    item.update(oldValue);
                &#125;);
            &#125;
        &#125;
        &#x2F;&#x2F; Watcher
        class Watcher &#123;
            constructor(node, key, vm) &#123;
                this.node &#x3D; node;
                this.key &#x3D; key;
                this.vm &#x3D; vm;
                Dep.curWatcher &#x3D; this;
                this.getData();
                Dep.curWatcher &#x3D; null;
            &#125;
            getData() &#123;
                return this.vm._data[this.key];
            &#125;
            update(oldValue) &#123;
                if (this.node.nodeType &#x3D;&#x3D; 1) &#123;
                    if (this.node.nodeName &#x3D;&#x3D;&#x3D; &quot;INPUT&quot;) &#123;
                        this.node.value &#x3D; this.getData();
                    &#125;
                    &#x2F;&#x2F; .....
                &#125; else &#123;
                    let oldText &#x3D; this.node.nodeValue;
                    this.node.nodeValue &#x3D; oldText.replace(oldValue, this.getData());
                &#125;
            &#125;
        &#125;

        class myVue &#123;
            constructor(options) &#123;
                let _this;
                &#x2F;&#x2F;&#x3D;&gt; init example
                this._data &#x3D; typeof options.data &#x3D;&#x3D;&#x3D; &quot;function&quot; ? options.data() : options.data;
                this.$el &#x3D; document.querySelector(options.el);

                &#x2F;&#x2F; data obServer
                this.obServer(this._data);

                &#x2F;&#x2F; nodeToFragment &amp;&amp; Compile
                this.nodeToFragment(this.$el);

                this.$root &#x3D; this;
                _this &#x3D; Object.assign(this._data, this);
                return _this;
            &#125;

            &#x2F;&#x2F; prototype
            obServer(data) &#123;
                if (data &amp;&amp; typeof data &#x3D;&#x3D;&#x3D; &quot;object&quot;) &#123;
                    for (let key in data) &#123;
                        if (!data.hasOwnProperty(key)) break;
                        this.defineReactive(data, key, data[key]);
                    &#125;
                &#125;
            &#125;
            &#x2F;&#x2F; data intercept
            defineReactive(data, key, value) &#123;
                this.obServer(value);
                const dep &#x3D; new Dep();
                let oldValue &#x3D; value;

                Object.defineProperty(data, key, &#123;
                    get() &#123;
                        if (Dep.curWatcher) &#123;
                            dep.subscribe(Dep.curWatcher);
                        &#125;
                        return value;
                    &#125;,
                    set(newValue) &#123;
                        if (newValue &#x3D;&#x3D;&#x3D; oldValue) return;
                        oldValue &#x3D; value;
                        value &#x3D; newValue;
                        dep.notify(oldValue);
                    &#125;
                &#125;);
            &#125;


            &#x2F;&#x2F; instruct-model
            instructModel(node, attr) &#123;
                &#x2F;&#x2F; 可根据input不同的type类型，设置不同的属性。  如： checked
                let nodeValue &#x3D; attr.nodeValue,
                    nodeName &#x3D; attr.nodeName;
                node.value &#x3D; this._data[nodeValue]; &#x2F;&#x2F; nodeValue 取到 data 中对应的字段
                node.removeAttribute(nodeName); &#x2F;&#x2F; 删除行间指令

                node.addEventListener(&quot;input&quot;, ev &#x3D;&gt; &#123;
                    this._data[nodeValue] &#x3D; ev.currentTarget.value;
                &#125;, false);
                &#x2F;&#x2F; 创建观察者（监听）
                new Watcher(node, nodeValue, this);
            &#125;
            &#x2F;&#x2F; Compile
            compile(node) &#123;
                if (node.nodeType &#x3D;&#x3D; 1) &#123;
                    &#x2F;&#x2F; 获取元素的节点的行间属性
                    let attrs &#x3D; node.attributes,
                        nodes &#x3D; node.childNodes;

                    for (let i &#x3D; 0; i &lt; attrs.length; i++) &#123;
                        let curAttr &#x3D; attrs[i],
                            curAttrName &#x3D; curAttr.nodeName;

                        if (&#x2F;^v\-&#x2F;.test(curAttrName)) &#123;
                            switch (curAttrName.substring(2)) &#123; &#x2F;&#x2F;&#x3D;&gt; 匹配对应v-指令
                                case &quot;model&quot;:
                                    this.instructModel(node, curAttr);
                                    break;
                                    &#x2F;&#x2F; .... 更多指令
                            &#125;;
                        &#125;
                    &#125;
                    &#x2F;&#x2F; 递归处理其子节点
                    for (let i &#x3D; 0; i &lt; nodes.length; i++) &#123;
                        this.compile(nodes[i]);
                    &#125;
                &#125; else &#123;
                    &#x2F;&#x2F; 解析非元素节点
                    let text &#x3D; node.nodeValue,
                        reg &#x3D; &#x2F;\&#123;\&#123;(.+?)\&#125;\&#125;&#x2F;g;

                    if (reg.test(text)) &#123;
                        text &#x3D; text.replace(reg, (g, key) &#x3D;&gt; &#123;
                            key &#x3D; key.trim();
                            if (key) new Watcher(node, key, this);
                            return this._data[key];
                        &#125;);
                        node.nodeValue &#x3D; text;
                    &#125;
                &#125;
            &#125;
            &#x2F;&#x2F; nodeToFragment
            nodeToFragment(element) &#123;
                let frag &#x3D; document.createDocumentFragment();
                let firstNode &#x3D; element.firstChild;

                while (firstNode) &#123;
                    frag.appendChild(firstNode);
                    this.compile(firstNode);
                    firstNode &#x3D; element.firstChild;
                &#125;
                element.appendChild(frag);
            &#125;
        &#125;;


        const myVm &#x3D; new myVue(&#123;
            el: &quot;#app&quot;,
            data() &#123;
                return &#123;
                    msg: &quot;这是一个动态添加的文本&quot;,
                    val: 666
                &#125;
            &#125;
        &#125;);
        console.log(myVm);


        &#x2F;&#x2F; const vm &#x3D; new Vue(&#123;
        &#x2F;&#x2F;     el: &quot;#app&quot;,
        &#x2F;&#x2F;     data() &#123;
