                () &#x3D;&gt; this.setState(mapStateToProps(this.context.store.getState()))
            );
        &#125;
        &#x2F;&#x2F; 取消订阅
        componentWillUnmount() &#123;
            this.unSubscribe();
        &#125;

        render() &#123;
            console.log(this);
            &#x2F;&#x2F; mapDispatchToProps : 除传入函数以外，在react-redux中:connect第二个参数还可以直接传入actions对象。
            &#x2F;&#x2F; 如果是函数，将store.dispatch传入，执行接收其返回值。
            &#x2F;&#x2F; 如果是对象，就会调用redux中的api--&gt; bindActionCreators(); 将对象传入，进行dispatch二次包装成函数
            let actions;
            if (typeof mapDispatchToProps &#x3D;&#x3D;&#x3D; &quot;function&quot;) &#123;
                actions &#x3D; mapDispatchToProps(this.context.store.dispatch);
            &#125; else if (typeof mapDispatchToProps &#x3D;&#x3D;&#x3D; &quot;object&quot; &amp;&amp; mapDispatchToProps !&#x3D;&#x3D; null) &#123;
                &#x2F;&#x2F; actions &#x3D; bindActionCreators(mapDispatchToProps, this.context.store.dispatch);  &#x2F;&#x2F; redux内置

                &#x2F;&#x2F; 既然写到这里了，就不用redux内置的bindActionCreators方法了。还是自己封装一个吧
                actions &#x3D; bindActionCreators(mapDispatchToProps, this.context.store.dispatch);
            &#125; else &#123;
                actions &#x3D; &#123;&#125;;
            &#125;

            &#x2F;&#x2F; 将指定的数据传入子组件，组件内部可以通过this.props获取
            return &lt;&gt;
                &lt;Component &#123;...this.state&#125; &#123;...actions&#125;&gt;&lt;&#x2F;Component&gt;
            &lt;&#x2F;&gt;
        &#125;
    &#125;
&#125;

&#x2F;&#x2F; 封装丐版 bindActionCreators  
const bindActionCreators &#x3D; (actionCreators, dispatch) &#x3D;&gt; &#123;
    const boundActionCreators &#x3D; &#123;&#125;;
    for (let key in actionCreators) &#123;
        const actionCreator &#x3D; actionCreators[key];
        if (typeof actionCreator &#x3D;&#x3D;&#x3D; &quot;function&quot;) &#123;
            boundActionCreators[key] &#x3D; function (...arg) &#123;
                dispatch(actionCreator.apply(this, arg));
            &#125;
        &#125;
    &#125;
    return boundActionCreators;
&#125;


export &#123;
    Provider,
    connect
&#125;

