    &#125;
    CreateDiv.prototype.create &#x3D; function () &#123;
        this.viewEle.style.width &#x3D; sw + &#39;px&#39;;
        this.viewEle.style.height &#x3D; sh + &#39;px&#39;;
        this.viewEle.style.position &#x3D; &#39;absolute&#39;;
        this.viewEle.style.left &#x3D; this.x + &#39;px&#39;;
        this.viewEle.style.top &#x3D; this.y + &#39;px&#39;;

        this.parent.appendChild(this.viewEle);

        return this;
    &#125;
    CreateDiv.prototype.remove &#x3D; function () &#123;
