    &#125;

    &#x2F;&#x2F; snake
    function Snake() &#123;
        this.head &#x3D; null;
        this.tail &#x3D; null;
        &#x2F;&#x2F; x,y all position
        this.pos &#x3D; [
            [2, 0],
            [1, 0],
            [0, 0]
        ];
        &#x2F;&#x2F; direction change
        this.directionStorage &#x3D; &#123;
            right: &#123;
                x: 1,
                y: 0
            &#125;,
            left: &#123;
                x: -1,
                y: 0
            &#125;,
            up: &#123;
                x: 0,
                y: -1
            &#125;,
            down: &#123;
                x: 0,
                y: 1
            &#125;
        &#125;;
        &#x2F;&#x2F; storage view
        this.snakeViewEle &#x3D; [];
    &#125;
    &#x2F;&#x2F; test next position
    Snake.prototype.PosTesting &#x3D; function () &#123;
        if (!game.timer) return;
        var nextPos &#x3D; &#123;
            x: this.head[0] + this.direction.x,
            y: this.head[1] + this.direction.y
        &#125;;
        &#x2F;&#x2F; console.log(nextPos);

        &#x2F;&#x2F; test food
        if (nextPos.x &#x3D;&#x3D;&#x3D; this.curFood.foodPos.x &amp;&amp; nextPos.y &#x3D;&#x3D;&#x3D; this.curFood.foodPos.y) &#123;
            this.eat();
