function deepClone(target) &#123;
    let result;
    let targetType &#x3D; &#123;&#125;.toString.call(target);
    if (targetType &#x3D;&#x3D;&#x3D; &quot;[object Object]&quot; || targetType &#x3D;&#x3D;&#x3D; &quot;[object Array]&quot;) &#123;
        targetType &#x3D; Array.isArray(target);
        result &#x3D; targetType ? [] : &#123;&#125;;
        for (let key in target) &#123;
            targetType ? result.push(deepClone(target[key])) : result[key] &#x3D; deepClone(target[key]);
        &#125;
    &#125; else &#123;
        result &#x3D; target;
    &#125;

    return result;
&#125;

